module.exports = {
  plugins: [
    plugin(function ({ addComponents, addUtilities, theme }) {
      // \u6DFB\u52A0\u7EC4\u4EF6
      addComponents({
        '.btn': {
          padding: theme('spacing.4'),
          borderRadius: theme('borderRadius.md'),
          fontWeight: theme('fontWeight.semibold'),
        },
      });

      // \u6DFB\u52A0\u5DE5\u5177\u7C7B
      addUtilities({
        '.content-auto': {
          contentVisibility: 'auto',
        },
      });
    }),

    // \u5B98\u65B9\u63D2\u4EF6
    require('@tailwindcss/forms'),
    require('@tailwindcss/typography'),
    require('@tailwindcss/aspect-ratio'),
  ],
};
`,paraId:144,tocIndex:60},{value:"\u9884\u8BBE\u7528\u4E8E\u5728\u591A\u4E2A\u9879\u76EE\u95F4\u5171\u4EAB\u914D\u7F6E\uFF1A",paraId:145,tocIndex:61},{value:`// my-preset.js
module.exports = {
  theme: {
    extend: {
      colors: {
        primary: '#1fb6ff',
        secondary: '#7e5bef',
      },
    },
  },
  plugins: [require('@tailwindcss/forms')],
};

// tailwind.config.js
module.exports = {
  presets: [require('./my-preset.js')],
  // \u9879\u76EE\u7279\u5B9A\u7684\u914D\u7F6E...
};
`,paraId:146,tocIndex:61},{value:"@config",paraId:83},{value:"\u5F53\u9700\u8981\u4E3A\u4E0D\u540C\u7684\u7AD9\u70B9\u751F\u6210\u4E0D\u540C\u7684\u6837\u5F0F\u6587\u4EF6\u65F6\uFF0C\u53EF\u4EE5\u4F7F\u7528 ",paraId:147,tocIndex:62},{value:"@config",paraId:147,tocIndex:62},{value:" \u6307\u4EE4\uFF1A",paraId:147,tocIndex:62},{value:`/* user.css - \u7528\u6237\u7AEF\u6837\u5F0F */
